/**
 * @summary Get bet analytics
 */
export const getGetBetAnalyticsUrl = (params?: GetBetAnalyticsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/bet-analytics?${stringifiedParams}`
    : `/api/admin/bet-analytics`;
};

export const getBetAnalytics = async (
  params?: GetBetAnalyticsParams,
  options?: RequestInit,
): Promise<BetAnalyticsResponse> => {
  return customFetch<BetAnalyticsResponse>(getGetBetAnalyticsUrl(params), {
    ...options,
    method: "GET",
  });
};

